// Step 1: Ingestion — normalize incoming message
const body = $input.first().json.body || $input.first().json;

const message = {
  id: `msg_${Date.now()}`,
  source: body.source || 'Unknown',
  timestamp: new Date().toISOString(),
  raw_message: body.raw_message || body.message || body.content || ''
};

if (!message.raw_message) {
  throw new Error('No message content found in request body');
}

return [{ json: message }];

// Parse classification response
const response = $input.first().json;
const content = response.content[0].text.trim();

let classification;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  classification = JSON.parse(clean);
} catch (e) {
  throw new Error(`Failed to parse classification JSON: ${content}`);
}

// Validate required fields
const validCategories = ['Bug Report', 'Feature Request', 'Billing Issue', 'Technical Question', 'Incident / Outage'];
const validPriorities = ['Low', 'Medium', 'High'];

if (!validCategories.includes(classification.category)) {
  throw new Error(`Invalid category: ${classification.category}`);
}
if (!validPriorities.includes(classification.priority)) {
  throw new Error(`Invalid priority: ${classification.priority}`);
}

// Merge with previous step data
const prev = $('Step 1: Ingestion').first().json;

return [{ json: { ...prev, classification } }];

