// Parse enrichment + run routing + escalation logic
const response = $input.first().json;
const content = response.content[0].text.trim();

let enrichment;
try {
  enrichment = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) {
  throw new Error(`Failed to parse enrichment JSON: ${content}`);
}

const prev = $('Parse Classification').first().json;
const { classification, raw_message } = prev;

// ── Routing table ──────────────────────────────────
const ROUTING = {
  'Bug Report': 'Engineering',
  'Incident / Outage': 'Engineering',
  'Feature Request': 'Product',
  'Technical Question': 'IT / Security',
  'Billing Issue': 'Billing'
};

// ── Escalation logic ───────────────────────────────
const ESCALATION_KEYWORDS = ['outage', 'down for all users', 'multiple users affected', 'stopped loading', 'completely down'];
const CONFIDENCE_THRESHOLD = 0.70;
const BILLING_THRESHOLD = 200;

let escalationFlag = false;
let escalationReason = null;
const msgLower = raw_message.toLowerCase();

if (classification.confidence_score < CONFIDENCE_THRESHOLD) {
  escalationFlag = true;
  escalationReason = `Confidence ${Math.round(classification.confidence_score * 100)}% below ${CONFIDENCE_THRESHOLD * 100}% threshold`;
}

if (!escalationFlag) {
  for (const kw of ESCALATION_KEYWORDS) {
    if (msgLower.includes(kw)) {
      escalationFlag = true;
      escalationReason = `Escalation keyword matched: '${kw}'`;
      break;
    }
  }
}

if (!escalationFlag && enrichment.identifiers?.discrepancy) {
  const discStr = enrichment.identifiers.discrepancy.replace(/[$,]/g, '');
  const disc = parseFloat(discStr);
  if (!isNaN(disc) && disc > BILLING_THRESHOLD) {
    escalationFlag = true;
    escalationReason = `Billing discrepancy $${disc} exceeds $${BILLING_THRESHOLD} threshold`;
  }
}

if (!escalationFlag && classification.category === 'Incident / Outage') {
  escalationFlag = true;
  escalationReason = 'Incident/Outage auto-escalates to Engineering via Escalation queue';
}

const destinationQueue = escalationFlag ? 'Escalation' : (ROUTING[classification.category] || 'Escalation');

const routing = {
  destination_queue: destinationQueue,
  routing_reason: escalationFlag ? escalationReason : `${classification.category} routes to ${destinationQueue} queue`,
  escalation_flag: escalationFlag,
  escalation_reason: escalationReason
};

return [{ json: { ...prev, enrichment, routing } }];

